<template>
  <div>
    <br>
<span>*********  微应用跳转   ************</span><br>	
	<input type='button' @click='microApp()' value='微应用跳转'></input>	   
<br>


	<br>
	<br>
<br>
  </div>
</template>

<script>
export default {
  name: "microApp", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    /**

	微应用跳转
	参数说明：
		appCode				目标应用 应用编码 

**/

    microApp() {
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        console.log("执行到这边表示cordova环境没有准备好");
        return;
      }
      alert("安装 全流程监控 应用");
      try {
        navigator.go.microApp(
          this.successCallback,
          this.errorCallback,
          "SNINTQLCJK"
        );
      } catch (ex) {
        console.log("try: " + ex.message);
      }
    },

    /**
	成功 回调
	参数说明：
		successCallback		成功回调	"code":0 成功	-2 应用不存在
**/
    successCallback(obj) {
      console.log(JSON.stringify(obj));
    },
    /**
	失败 回调
	参数说明：
		errorCallback		失败回调	"code":-1 参数错误 -3 内部错误(errorcallback)
**/
    errorCallback(obj) {
      console.log(JSON.stringify(obj));
    },
  },
};
</script>
